  "dependencies": {
    "parallel_units": true,
    "edges": [
      {
        "from": "security_check_batch",
        "to": "shared_report_markdown",
        "type": "mutation",
        "reason": "otherwise independent workers currently append to the same report.md file and therefore contend on a shared mutable target"
      }
    ],
    "capacity_constraints": []
  },
  "dynamic": {
    "batch": {
      "handle": "security_check_batch",
      "item_identity_source": "route_launch_snapshot"
    },
    "await": {
      "join": "all",
      "k": null,
      "quorum_basis": null,
      "eligible_identity_source": "route_launch_snapshot",
      "eligible_statuses": ["succeeded", "failed", "cancelled", "timed_out"],
      "wake_event": "security_check_batch_settled"
    },
    "accounting": {
      "expected_identity_source": "route_launch_snapshot",
      "observed_record_scope": "all_received_records_including_unknown",
      "terminal_statuses": ["succeeded", "failed", "cancelled", "timed_out"],
      "duplicate_policy": "open",
      "unknown_policy": "open",
      "failure_policy": "open",
      "partial_policy": "open",
      "complete_label_requires": [
        "expected_vs_represented",
        "no_duplicates",
        "no_unknown_identities",
        "terminal_status_accounted",
        "no_unresolved_identities"
      ]
    },
    "reductions": [
      {
        "name": "security_check_batch_summary_layer",
        "expected_identity_source": "route_launch_snapshot",
        "observed_result_source": "received_security_check_result_records",
        "represented_identity_source": "identities_extracted_from_received_security_check_results",
        "represented_identity_derivation": "from_observed_results",
        "status_count_source": "statuses_from_received_security_check_results",
        "unresolved_identity_source": "expected_minus_observed_security_check_identities",
        "output_summary_identity_source": "emitted_security_check_batch_summary_manifest"
      }
    ],
    "final_reconciliation": {
      "expected_summary_identity_source": "emitted_security_check_batch_summary_manifest",
      "observed_summary_source": "received_security_check_batch_summary_records",
      "represented_identity_derivation": "from_observed_summaries",
      "checks": [
        "expected_vs_represented",
        "duplicate",
        "unknown",
        "terminal_status",
        "unresolved"
      ]
    }
  },
  "open_points": [
    {
      "key": "duplicate_policy",
      "question": "If more than one result record is received for the same security check identity, should completion be rejected or can one record be accepted for reporting?"
    },
    {
      "key": "unknown_policy",
      "question": "If a result record arrives for an identity not present in the launched 20-check snapshot, should synthesis reject completion or tolerate the unknown record as represented-only?"
    },
    {
      "key": "failure_policy",
      "question": "Does any failed security check block synthesis of the final report or can synthesis proceed with failures represented?"
    },
    {
      "key": "partial_policy",
      "question": "May the workflow emit a partial report when some of the 20 expected security checks remain unresolved or missing?"
    }
  ],
  "scenarios": [
    {
      "kind": "positive",
      "expected": "complete_after_full_reconciliation"
    },
    {
      "kind": "missing",
      "expected": "missing_expected_identity_blocks_complete"
    },
    {
      "kind": "duplicate",
      "expected": "duplicate_blocks_complete"
    },
    {
      "kind": "failed",
      "expected": "failed_identity_blocks_complete"
    },
    {
      "kind": "timed_out",
      "expected": "timed_out_identity_blocks_complete"
    },
    {
      "kind": "unknown",
      "expected": "unknown_record_represented_excluded_from_join_blocks_complete"
    },
    {
      "kind": "partial_refused",
      "expected": "hypothetical_refusal_if_policy_rejects"
    },
    {
      "kind": "partial_allowed",
      "expected": "hypothetical_incomplete_label_if_policy_allows"
    }
  ],
  "boundary": {
    "control_plane": ["launch", "await", "accounting", "reconciliation"],
    "target_data_plane": ["workers", "scheduling", "persistence", "shared_report_mutation"]
  }
}

